histrix.customScript:
			window.setTimeout(function(){
        		$('[campo="no_conformidad"] > div').css({'border':'0px'});
			}, 1000);


			$('td[campo="observacion_inspec"] input', $('td[campo="no_conforme"] input:checkbox:checked').closest('tr')).show();

			$('td[campo="no_conformidad"] input', $('td[campo="no_conforme"] input:checkbox:checked').closest('tr')).show();


        	$('td[campo="conforme"] input:checkbox').change(function(){
        		var tr = $(this).closest('tr');

				$('[campo="no_conformidad"]', tr).show();

				$('[campo="no_conformidad"]', tr).each(function(){
				    	if ($(this).val() == '') 
						$(this).hide();
				});

        		if ($(this).prop('checked')){

	        		$(tr).css({'background-color':'greenyellow'});

    	    		var $noconf = $('td[campo="no_conforme"] input:checkbox', tr).prop('checked', !$(this).prop('checked'));

					try {
					    $noconf.checkboxradio("refresh");
					} catch (err){$('[name="controlcausal_id"]', tr)
				    	// no es movil
					}

        		} else {
        			tr.css({'background-color':'transparent'});
        		}
        	});


        	$('td[campo="no_conforme"] input:checkbox').change(function(){
        		var tr = $(this).closest('tr');


        		if ($(this).prop('checked')){
        			$('[name="observacion_inspec"]', tr).show();
        			$('[campo="no_conformidad"]', tr).show();


	        		tr.css({'background-color':'transparent'});
	        		var $conf = $('td[campo="conforme"] input:checkbox', tr).prop('checked', !$(this).prop('checked'));

				try {
				    $conf.checkboxradio("refresh");
				} catch (err){ tr.css({'background-color':'transparent'});
				    // no es movil
				}


        		} else {
        			$('td[campo="observacion_inspec"] input', tr).hide();
        			$('td[campo="no_conformidad"] input', tr).hide();
        		}
        	});        	


				$('td[campo="conforme"] input:checkbox, td[campo="no_conforme"] input:checkbox', tr).closest('td').css({'background-color':'transparent'});
        		} else {
	        		var $conf = $('td[campo="conforme"] input:checkbox, td[campo="no_conforme"] input:checkbox', tr).prop('checked', $(this).prop('checked')).prop('disabled',false).checkboxradio("refresh");

				try {
				    $conf.checkboxradio("refresh");
				} catch (err){
				    // no es movil
				}

				tr.css({'background-color':'transparent' ,  'text-decoration':'none'});
        		//	$('td[campo="observacion_inspec"] input', tr).show();
        		}
        	});
